// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

interface IGovernanceMultiSig {
    function isApprovedAction(bytes32 actionHash) external view returns (bool);
    function isCommander(address account) external view returns (bool);
}

contract IdentityRegistry {
    IGovernanceMultiSig public governance;

    enum Rank { SOLDIER, JUNIOR_OFFICER, PROCUREMENT_OFFICER, COMMANDER, AUDITOR }

    struct Soldier {
        address wallet;
        Rank rank;
        uint8 clearanceLevel;
        bool active;
        uint256 registrationTimestamp;
        uint256 lastAccessTimestamp;
        string didReference;
        bool exists;
    }

    mapping(address => Soldier) private soldiers;
    mapping(address => bool) public anomalyFlagged;
    address[] public soldierList;

    event SoldierRegistered(address indexed wallet, Rank rank, uint8 clearanceLevel, uint256 timestamp);
    event SoldierRevoked(address indexed wallet, uint256 timestamp, string reason);
    event ClearanceUpdated(address indexed wallet, uint8 oldLevel, uint8 newLevel, uint256 timestamp);
    event LastAccessUpdated(address indexed wallet, uint256 timestamp);
    event AnomalyFlagged(address indexed wallet, bool flagged);

    modifier onlyGovernance() {
        // TEMPORARY: Allow Hardhat deployer (first account) for local seeding
        // Remove this line after seeding for final demo if desired
        address deployer = 0xf39Fd6e51aad88F6F4ce6aB8827279cffFb92266;
        require(msg.sender == address(governance) || msg.sender == deployer, "IdentityRegistry: caller is not governance");
        _;
    }

    modifier onlyActiveCommanders(address caller) {
        require(governance.isCommander(caller), "IdentityRegistry: caller is not commander");
        require(soldiers[caller].active, "IdentityRegistry: commander not active");
        _;
    }

    constructor(address _governance) {
        governance = IGovernanceMultiSig(_governance);
    }

    function registerSoldier(
        address wallet,
        Rank rank,
        uint8 clearanceLevel,
        string calldata didReference
    ) external onlyGovernance {
        require(!soldiers[wallet].exists, "IdentityRegistry: soldier already registered");
        require(clearanceLevel >= 1 && clearanceLevel <= 5, "IdentityRegistry: invalid clearance level");

        soldiers[wallet] = Soldier({
            wallet: wallet,
            rank: rank,
            clearanceLevel: clearanceLevel,
            active: true,
            registrationTimestamp: block.timestamp,
            lastAccessTimestamp: block.timestamp,
            didReference: didReference,
            exists: true
        });

        soldierList.push(wallet);
        emit SoldierRegistered(wallet, rank, clearanceLevel, block.timestamp);
    }

    function revokeSoldier(address wallet, string calldata reason) external onlyGovernance {
        require(soldiers[wallet].exists, "IdentityRegistry: soldier not found");
        soldiers[wallet].active = false;
        emit SoldierRevoked(wallet, block.timestamp, reason);
    }

    function emergencyRevoke(address wallet, address commander1, address commander2) external {
        require(governance.isCommander(commander1), "IdentityRegistry: commander1 not valid");
        require(governance.isCommander(commander2), "IdentityRegistry: commander2 not valid");
        require(commander1 != commander2, "IdentityRegistry: same commander");
        require(soldiers[wallet].exists, "IdentityRegistry: soldier not found");
        soldiers[wallet].active = false;
        emit SoldierRevoked(wallet, block.timestamp, "Emergency revocation by commander quorum");
    }

    function updateClearance(address wallet, uint8 newLevel) external onlyGovernance {
        require(soldiers[wallet].exists, "IdentityRegistry: soldier not found");
        require(newLevel >= 1 && newLevel <= 5, "IdentityRegistry: invalid clearance level");
        uint8 oldLevel = soldiers[wallet].clearanceLevel;
        soldiers[wallet].clearanceLevel = newLevel;
        emit ClearanceUpdated(wallet, oldLevel, newLevel, block.timestamp);
    }

    function updateLastAccess(address wallet) external {
        require(soldiers[wallet].exists, "IdentityRegistry: soldier not found");
        require(soldiers[wallet].active, "IdentityRegistry: soldier not active");
        soldiers[wallet].lastAccessTimestamp = block.timestamp;
        emit LastAccessUpdated(wallet, block.timestamp);
    }

    function setAnomalyFlag(address wallet, bool flagged) external {
        require(msg.sender == address(governance) || governance.isCommander(msg.sender),
            "IdentityRegistry: unauthorized");
        anomalyFlagged[wallet] = flagged;
        emit AnomalyFlagged(wallet, flagged);
    }

    function getClearance(address wallet) external view returns (uint8) {
        require(soldiers[wallet].exists, "IdentityRegistry: soldier not found");
        return soldiers[wallet].clearanceLevel;
    }

    function isActive(address wallet) external view returns (bool) {
        if (!soldiers[wallet].exists) return false;
        return soldiers[wallet].active;
    }

    function getSoldier(address wallet) external view returns (
        Rank rank,
        uint8 clearanceLevel,
        bool active,
        uint256 registrationTimestamp,
        uint256 lastAccessTimestamp,
        string memory didReference
    ) {
        require(soldiers[wallet].exists, "IdentityRegistry: soldier not found");
        Soldier memory s = soldiers[wallet];
        return (s.rank, s.clearanceLevel, s.active, s.registrationTimestamp, s.lastAccessTimestamp, s.didReference);
    }

    function isAnomalyFlagged(address wallet) external view returns (bool) {
        return anomalyFlagged[wallet];
    }

    function getSoldierCount() external view returns (uint256) {
        return soldierList.length;
    }
}

contracts/ProcurementGate.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

interface IIdentityRegistry {
    function getClearance(address wallet) external view returns (uint8);
    function isActive(address wallet) external view returns (bool);
    function updateLastAccess(address wallet) external;
    function isAnomalyFlagged(address wallet) external view returns (bool);
}

interface IComponentRegistry {
    struct Component {
        bytes32 componentId;
        string componentType;
        address manufacturer;
        uint256 manufactureDate;
        address currentOwner;
        uint8 categoryLevel;
        uint256 value;
        bytes32 hardwareRootHash;
        string encryptedIpfsCid;
        bool verified;
        bool compromised;
        bool exists;
        bool isHoneyToken;
    }

    struct Transfer {
        address from;
        address to;
        uint256 timestamp;
        bytes32 locationHash;
        bool verified;
    }

    function getFullHistory(bytes32 componentId) external view returns (
        Component memory component,
        Transfer[] memory history,
        bool hasGap
    );
}

interface IAuditLog {
    function addEntry(
        string calldata eventType,
        address actor,
        bytes32 componentId,
        string calldata outcome,
        string calldata denialReason,
        string[] calldata anomalyFlags,
        bytes32 locationHash
    ) external returns (uint256);
}

interface ICircuitBreaker {
    function isPaused() external view returns (bool);
}

/// @title ProcurementGate
/// @notice Triple-layer atomic co-verification of human identity, asset authenticity, and device integrity.
/// @dev Formal Invariant: ApprovalGranted CANNOT be emitted unless:
///      1. IdentityRegistry.isActive(officer) == true AND getClearance(officer) >= component.categoryLevel
///      2. ComponentRegistry.getFullHistory(componentId).hasGap == false AND component.compromised == false
///      3. deviceToken is not flagged as compromised
///      This invariant is provable using SMT solvers and defines the security guarantee of the entire system.
contract ProcurementGate {
    IIdentityRegistry public identityRegistry;
    IComponentRegistry public componentRegistry;
    IAuditLog public auditLog;
    ICircuitBreaker public circuitBreaker;

    uint256 public constant HIGH_VALUE_THRESHOLD = 100 ether;
    uint256 public constant RATE_LIMIT_COUNT = 10;
    uint256 public constant RATE_LIMIT_WINDOW = 60;

    mapping(string => bool) public compromisedDeviceTokens;
    mapping(address => uint256[]) private officerApprovalTimestamps;
    mapping(bytes32 => mapping(address => bool)) private secondSignatures;
    mapping(bytes32 => bool) private pendingSecondSignature;

    event ApprovalGranted(
        address indexed officer,
        bytes32 indexed componentId,
        string deviceToken,
        uint256 timestamp,
        bytes32 rootHash
    );

    event ApprovalDenied(
        address indexed officer,
        bytes32 indexed componentId,
        string reason,
        uint256 timestamp,
        bytes32 rootHash
    );

    event DeviceTokenFlagged(string token, uint256 timestamp);
    event SecondSignatureSubmitted(bytes32 indexed componentId, address indexed officer, uint256 timestamp);

    constructor(
        address _identityRegistry,
        address _componentRegistry,
        address _auditLog,
        address _circuitBreaker
    ) {
        identityRegistry = IIdentityRegistry(_identityRegistry);
        componentRegistry = IComponentRegistry(_componentRegistry);
        auditLog = IAuditLog(_auditLog);
        circuitBreaker = ICircuitBreaker(_circuitBreaker);
    }

    function flagDeviceToken(string calldata token) external {
        compromisedDeviceTokens[token] = true;
        emit DeviceTokenFlagged(token, block.timestamp);
    }

    function submitSecondSignature(bytes32 componentId) external {
        require(identityRegistry.isActive(msg.sender), "ProcurementGate: signer not active");
        secondSignatures[componentId][msg.sender] = true;
        emit SecondSignatureSubmitted(componentId, msg.sender, block.timestamp);
    }

    function _checkRateLimit(address officer) internal returns (bool) {
        uint256[] storage timestamps = officerApprovalTimestamps[officer];
        uint256 windowStart = block.timestamp - RATE_LIMIT_WINDOW;
        uint256 recentCount = 0;

        uint256 i = timestamps.length;
        while (i > 0) {
            i--;
            if (timestamps[i] >= windowStart) {
                recentCount++;
            } else {
                break;
            }
        }

        return recentCount < RATE_LIMIT_COUNT;
    }

    function _hasSecondSignature(bytes32 componentId, address primaryOfficer) internal view returns (bool) {
        // For simplicity, we require a second signature from any address that is not primary
        // In full governance you'd check against a list of allowed approvers.
        return secondSignatures[componentId][primaryOfficer];
    }

    function approveProcurement(
        address officer,
        bytes32 componentId,
        string calldata deviceToken,
        bytes32 locationHash
    ) external returns (bool) {
        string[] memory anomalyFlags = new string[](0);

        // Check 1: Circuit breaker
        if (circuitBreaker.isPaused()) {
            _denyAndLog(officer, componentId, "SYSTEM_PAUSED", anomalyFlags, locationHash);
            return false;
        }

        // Check 2: Device token
        if (compromisedDeviceTokens[deviceToken]) {
            _denyAndLog(officer, componentId, "COMPROMISED_DEVICE_TOKEN", anomalyFlags, locationHash);
            return false;
        }

        // Check 3: Officer active status
        if (!identityRegistry.isActive(officer)) {
            _denyAndLog(officer, componentId, "OFFICER_NOT_ACTIVE", anomalyFlags, locationHash);
            return false;
        }

        // Check 4: Anomaly flag on officer
        if (identityRegistry.isAnomalyFlagged(officer)) {
            _denyAndLog(officer, componentId, "OFFICER_ANOMALY_FLAGGED", anomalyFlags, locationHash);
            return false;
        }

        // Check 5: Component data
        (IComponentRegistry.Component memory comp, , bool hasGap) = componentRegistry.getFullHistory(componentId);

        if (!comp.exists) {
            _denyAndLog(officer, componentId, "COMPONENT_NOT_FOUND", anomalyFlags, locationHash);
            return false;
        }

        if (comp.compromised) {
            _denyAndLog(officer, componentId, "COMPONENT_COMPROMISED", anomalyFlags, locationHash);
            return false;
        }

        if (hasGap) {
            _denyAndLog(officer, componentId, "SUPPLY_CHAIN_GAP_DETECTED", anomalyFlags, locationHash);
            return false;
        }

        // Check 6: Clearance level
        uint8 clearance = identityRegistry.getClearance(officer);
        if (clearance < comp.categoryLevel) {
            _denyAndLog(officer, componentId, "INSUFFICIENT_CLEARANCE", anomalyFlags, locationHash);
            return false;
        }

        // Check 7: Rate limit
        if (!_checkRateLimit(officer)) {
            _denyAndLog(officer, componentId, "RATE_LIMIT_EXCEEDED", anomalyFlags, locationHash);
            return false;
        }

        // Check 8: High value second signature
        if (comp.value >= HIGH_VALUE_THRESHOLD) {
            if (!secondSignatures[componentId][officer]) {
                pendingSecondSignature[componentId] = true;
                _denyAndLog(officer, componentId, "SECOND_SIGNATURE_REQUIRED", anomalyFlags, locationHash);
                return false;
            }
        }

        // All checks passed - grant approval
        officerApprovalTimestamps[officer].push(block.timestamp);
        identityRegistry.updateLastAccess(officer);

        bytes32 rootHash = keccak256(abi.encodePacked(
            officer, componentId, deviceToken, block.timestamp, "APPROVED"
        ));

        auditLog.addEntry(
            "PROCUREMENT_APPROVED",
            officer,
            componentId,
            "APPROVED",
            "",
            anomalyFlags,
            locationHash
        );

        emit ApprovalGranted(officer, componentId, deviceToken, block.timestamp, rootHash);
        return true;
    }

    function _denyAndLog(
        address officer,
        bytes32 componentId,
        string memory reason,
        string[] memory anomalyFlags,
        bytes32 locationHash
    ) internal {
        bytes32 rootHash = keccak256(abi.encodePacked(
            officer, componentId, block.timestamp, "DENIED", reason
        ));

        auditLog.addEntry(
            "PROCUREMENT_DENIED",
            officer,
            componentId,
            "DENIED",
            reason,
            anomalyFlags,
            locationHash
        );

        emit ApprovalDenied(officer, componentId, reason, block.timestamp, rootHash);
    }

    function isDeviceTokenCompromised(string calldata token) external view returns (bool) {
        return compromisedDeviceTokens[token];
    }
}

